void ApplyMigrations(AppDbContext db)
{
    // EF Core 9 manages its own transactions during Migrate(); wrapping in
    // a user transaction now throws. The execution strategy is also handled
    // internally, so a plain call is sufficient.
    db.Database.Migrate();
}

