using Microsoft.EntityFrameworkCore;

/// <summary>
/// Demonstrates the three Cosmos DB EF Core 9 breaking changes and their fixes.
/// Add Microsoft.EntityFrameworkCore.Cosmos 9.0.0 to your Cosmos project.
/// </summary>
class CosmosContext : DbContext
{
    public DbSet<Session> Sessions => Set<Session>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // FIX 1 — Discriminator property renamed to "$type" in EF Core 9.
        // Existing documents use "Discriminator", so explicitly preserve the old name.
        modelBuilder.Entity<Session>().HasDiscriminator<string>("Discriminator");

        // FIX 2 — id property no longer embeds the discriminator by default.
        // Existing documents have ids like "Session|42". Preserve that format.
        modelBuilder.Entity<Session>().HasRootDiscriminatorInJsonId(true);
    }

    // FIX 3 — Synchronous I/O is no longer supported by the Cosmos DB provider.
    // All queries and saves must use async equivalents.
    //
    //   BEFORE (throws in EF Core 9):
    //     var sessions = db.Sessions.ToList();
    //     db.SaveChanges();
    //
    //   AFTER:
    //     var sessions = await db.Sessions.ToListAsync();
    //     await db.SaveChangesAsync();
}

class Session
{
    public int Id { get; set; }
    public string? Name { get; set; }
}

